// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../../types';
import { CharacterId } from '../../../../characters';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聽到能回到自己世界的希望，李杰的心情激動不已。他深吸了一口氣，努力讓自己的聲音聽起來不那麼顫抖。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "艾拉如先生，請問...您知道他們是怎麼回去的嗎？我們該怎麼做才能找到那個方法？" },
    { characterId: CharacterId.Ailaru, character: "艾拉如", dialogue: "(輕輕搖了搖頭，銀色的長髮隨之輕擺，在光芒中閃爍) 很抱歉，年輕人。我對此知之甚少。那個故事...也是從我的兒子口中聽來的。他曾接待過那些人類，陪伴他們度過了在這裡的時光，對此可能了解更多。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(急切地追問) 那...我們可以見見您的兒子嗎？他現在在哪裡？" },
    { characterId: CharacterId.Ailaru, character: "艾拉如", dialogue: "(眼神望向遠方的山谷，帶著一絲歉意) 他目前不在村莊裡。月光林地之外還有許多地方需要他的力量與智慧。不過，我想他很快就會回來了。" },
    { characterId: CharacterId.Ailaru, character: "艾拉如", dialogue: "(轉回視線，溫和地看著兩人) 你們長途跋涉，想必已經非常疲憊了。看看你們的衣服和鞋子，還沾著森林的泥土和露水。不如先到為你們準備的住處好好休息，洗個熱水澡，吃頓熱飯。等他回來，我再帶你們去見他。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰和清水對視一眼。清水的臉色確實蒼白，眼下有著淡淡的黑眼圈，腳步也有些虛浮。李杰自己也感覺到雙腿的沉重和肩膀的酸痛。疲憊的身體確實難以支撐他們繼續追問。這個建議再好不過了。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(點頭，真誠地說) 那就麻煩您了，艾拉如先生。我們...確實需要休息。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "艾拉如微笑著轉身，帶他們沿著村莊的小路前行。路面由平整的白色石板鋪成，兩旁種滿了那些會發光的植物。偶爾有精靈經過，都會好奇地看向他們，然後友善地點頭微笑。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們經過溪流上的一座小橋，橋身由藤蔓編織而成，卻堅固穩當。清澈的溪水在橋下流淌，可以看到水底的鵝卵石和游動的銀色小魚。空氣中飄散著花香和青草的清新氣息，讓人不由得放鬆下來。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走了約五分鐘，艾拉如帶他們來到村莊邊緣的一間小屋。這間小屋座落在一棵巨大的古樹旁，由同樣的白色岩石和木材建造，屋頂覆蓋著銀綠色的苔蘚。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "外觀簡潔而優雅，門前種著幾株會發光的花朵，窗戶是半圓形的，透著溫暖的光。整座小屋看起來彷彿是從大自然中生長出來的，與周圍的環境完美融合。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "推開木門，內部的景象讓李杰和清水都不由得倒吸一口氣——這裡比他們在迷霧森林裡的那間簡陋小屋豪華太多了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "客廳寬敞明亮，地板由打磨光滑的白色石材鋪成，上面鋪著柔軟的地毯，織紋精美如同藝術品。牆壁是原木與白石交織而成，嵌著幾塊發光的水晶，散發著柔和的光芒。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "家具都是精雕細琢的作品——沙發上覆蓋著絲綢般的布料，茶几是一整塊透明的水晶打磨而成，可以看到裡面凝固著美麗的花瓣。書架上擺放著裝訂精美的書籍和一些精緻的擺飾。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "最驚人的是天花板——由活的藤蔓編織而成，上面開著許多小巧的發光花朵，像是一片倒掛的星空。整個空間散發著淡淡的花香和木頭的清香，優雅而不失溫馨。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(環顧四周，有些不好意思) 這...這太好了...我們..." },
    { characterId: CharacterId.Ailaru, character: "艾拉如", dialogue: "(溫和地笑了笑) 不必拘謹。這是我們為遠道而來的客人準備的客房。你們長途跋涉，理應得到最好的休息。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(想起了什麼，忍不住開口) 艾拉如先生，請問...您知道迷霧森林裡的那種小木屋嗎？我們昨晚就在那裡休息的。" },
    { characterId: CharacterId.Ailaru, character: "艾拉如", dialogue: "(眼中閃過一絲了然) 哦，你說的是我們的獵戶小屋吧？它們散落在迷霧之森的各處，是我們巡邏和狩獵時的補給點。你們能夠找到並使用它，那是你們的幸運。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰心中恍然。原來那不是什麼神秘的存在，而是精靈們的設施。但他心中的疑惑並未完全消散——為何那間小屋如此整潔，卻又沒有精靈的蹤跡？床鋪和廚房都像是剛剛被使用過的樣子。還有那兩把準備好的廚房刀..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但疲憊讓他暫時放下了這些疑問。或許之前有其他巡邏的精靈用過，只是剛好錯開了。" },
    { characterId: CharacterId.Ailaru, character: "艾拉如", dialogue: "(看了看屋內，滿意地點點頭) 好了，兩位。這裡就是你們的住處了。廚房裡有一些食材，浴室裡有熱水——我們用地底的溫泉加熱，隨時都是溫暖的。請好好享受這裡的寧靜時光。有任何需要，都可以到村中央找我。我先告辭了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "艾拉如輕輕頷首，銀色的長髮在光芒中劃過一道優雅的弧線，然後緩慢而優雅地轉身離開。木門關上後，小屋裡只剩下李杰和清水兩人。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰環顧四周。這間屋子比迷霧森林中的那間更大，客廳裡有兩張柔軟的沙發和一張矮桌，牆上掛著一幅用樹葉和花瓣拼成的裝飾畫。廚房裡的櫥櫃整齊排列，散發著木頭的清香。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "最引人注目的是屋子裡也有那些會發光的植物，被種在精緻的陶罐裡，放在窗台和桌上，提供著柔和的照明。整個空間溫馨而寧靜，讓人不由得想要放下所有防備。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(看著小屋，眼中閃爍著興奮的光芒) 好溫馨的地方...李杰先生，我先去洗澡了..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "嗯，妳去吧。我等一下。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "清水走進其中一間臥室，不久後傳來水聲。李杰坐在沙發上，終於有時間整理一下思緒。從那個詭異的列車、寂海車站、迷霧森林，到現在的精靈村莊...這一切都太過超現實。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但那個艾拉如說的話給了他希望——兩年前的那些人類回去了。這意味著他們也有機會回去。他只需要等艾拉如的兒子回來，問清楚方法。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "約二十分鐘後，清水洗完澡走了出來。她換上了臥室衣櫃裡找到的一件簡單的白色長袍——看起來是精靈的衣服，但尺寸剛好合適。她的頭髮還有些濕潤，散發著清新的香氣，臉色也比之前好了許多。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(有些不好意思地說) 李杰先生...衣櫃裡有乾淨的衣服...我的衣服太髒了，就先換上了..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(笑了笑) 沒關係。我也去洗一下。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰走進另一間臥室。浴室裡果然有溫暖的熱水，洗去了他身上的疲憊和森林的塵土。他也換上了衣櫃裡的精靈長袍，布料輕盈柔軟，穿起來出乎意料地舒適。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "當他走出浴室時，已經聞到了食物的香氣。清水正在廚房裡忙碌著，她找到了一些奇異的植物——有的像是蘿蔔，有的像是菌菇，還有一些不知名的穀物。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(從廚房裡端出兩碗熱氣騰騰的湯和一盤烤過的麵包) 李杰先生，這些植物聞起來好香，我試著煮了一下。應該...應該可以吃..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰接過碗，湯汁呈現淡綠色，飄散著清新的草本香氣。他嘗了一口，味道出乎意料地鮮美，帶著一絲甜味，溫暖地滑過喉嚨。麵包也很鬆軟，帶著淡淡的堅果香。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "晚餐雖然簡樸，卻是他們來到這個世界後吃過最美味的一餐。或許是因為終於有了希望，又或許是精靈村莊的寧靜讓他們能夠真正放鬆下來。他們邊吃邊聊，話題圍繞著回到現實世界後的計劃。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(吃了一口湯，感嘆地說) 說真的，我從來沒想過自己會這麼想念公司裡那台嗡嗡作響的電腦。回去以後，我一定要先去常去的那家拉麵店，吃一碗特大碗的豚骨拉麵。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(輕輕笑了起來，眼中帶著憧憬) 我...我想回學校的圖書館。那裡有種舊書的味道，很讓人安心。還有...還有我最喜歡的那個靠窗的座位..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(認真地看著她) 真希望明天就能見到艾拉如的兒子，問清楚回去的方法。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(點點頭，眼中閃爍著希望的光芒) 嗯！一定可以的！我們一定能回去！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "晚餐後，兩人各自選了一個臥室。臥室裡的床鋪柔軟舒適，被褥散發著陽光和花草的清香。窗外是寧靜的村莊，發光的植物像星星一樣點綴在夜色中。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰躺在床上，聽著窗外溪水流淌的聲音和遠處精靈們悠揚的歌聲。這是他們來到這個世界後，第一個真正安心的夜晚。疲憊如潮水般湧來，他很快就沉沉地睡去。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "窗外的月光柔和地灑在村莊上，精靈們的歌聲逐漸消散，一切都顯得如此寧靜祥和。時間在這片銀藍色的光暈中緩緩流逝。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不知過了多久，李杰在深沉的睡眠中緩緩醒來。最初，他以為是自然醒來，但隨即察覺到一絲異樣——空氣中似乎有種說不出的緊張感。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "當他睜開雙眼時，卻完全無法相信眼前的景象。" },
];
